mapper.update:
UPDATE om_menu_m
   SET menu_nm = CAST(#{menuNm} AS JSONB)
     , menu_url = #{menuUrl,jdbcType=VARCHAR}
     , is_active = #{isActive}
     , icon = #{icon,jdbcType=VARCHAR}
     , disp_seq = #{dispSeq}
     , menu_info = CAST(#{menuInfo} AS JSONB)
     , updated_by = #{userId}
     , updated_at = CURRENT_TIMESTAMP
 WHERE menu_id = #{menuId}
   AND is_deleted = false
